# From tab_matlab.py — engine start handler
import matlab.engine

class MatlabEngineTab(QWidget):
    def start_engine(self):
        self.status_label.setText("Starting MATLAB Engine...")
        self.start_btn.setEnabled(False)

        # Run in background thread to avoid UI freeze
        worker = MatlabStartWorker()
        worker.engine_ready.connect(self.on_engine_ready)
        worker.error.connect(self.on_engine_error)
        worker.start()

class MatlabStartWorker(QThread):
    engine_ready = pyqtSignal(object)  # matlab.engine instance
    error        = pyqtSignal(str)

    def run(self):
        try:
            # Connect to existing MATLAB session if available,
            # otherwise start a new one:
            existing = matlab.engine.find_matlab()
            if existing:
                eng = matlab.engine.connect_matlab(existing[0])
            else:
                eng = matlab.engine.start_matlab()
            self.engine_ready.emit(eng)
        except Exception as e:
            self.error.emit(str(e))

# From tab_matlab.py — clean shutdown
def stop_engine(self):
    if self.eng is not None:
        try:
            self.eng.quit()  # Gracefully terminate MATLAB session
        except Exception:
            pass  # Already closed
        finally:
            self.eng = None
            self.status_label.setText("MATLAB: DISCONNECTED")
            self.log("MATLAB Engine stopped")
